const body = $input.first().json.body;
const entry = body.entry[0].changes[0].value;
const msg = entry.messages[0];
const contact = entry.contacts ? entry.contacts[0] : null;

return [{
  json: {
    phone: msg.from,
    message: msg.text.body,
    sender_name: contact ? contact.profile.name : 'Desconocido',
    message_id: msg.id,
    timestamp: msg.timestamp
  }
}];

const items = $input.all();
const parseData = items[0].json;

// Get previous node data (Parse WA Data)
const phone = $('Parse WA Data').first().json.phone;
const message = $('Parse WA Data').first().json.message;
const sender_name = $('Parse WA Data').first().json.sender_name;
const message_id = $('Parse WA Data').first().json.message_id;

// Get lead state from Supabase (may be empty array)
let leadData = {};
if (Array.isArray(parseData) && parseData.length > 0) {
  leadData = parseData[0];
} else if (parseData && parseData.phone) {
  leadData = parseData;
}

let history = [];
if (leadData.conversation_history) {
  try {
    history = typeof leadData.conversation_history === 'string' 
      ? JSON.parse(leadData.conversation_history) 
      : leadData.conversation_history;
  } catch(e) { history = []; }
}

// Add current message
history.push({ role: 'user', content: message });

// Keep last 20 messages
if (history.length > 20) history = history.slice(-20);

return [{
  json: {
    phone,
    sender_name,
    message_id,
    messages: history,
    lead_exists: !!leadData.phone,
    lead_status: leadData.lead_status || 'nuevo',
    filtro_actual: leadData.filtro_actual || 1
  }
}];

const prev = $('Build Context').first().json;
const slotsResp = $('Get Available Slots').first().json;

let slotsText = '';
try {
  const slots = slotsResp.slots || [];
  const duration = slotsResp.duration || 30;
  if (slots.length > 0) {
    slotsText = '[HORARIOS_DISPONIBLES]\nDuración de cita: ' + duration + ' minutos\nConsultora: Ingrid Escobar\n\n';
    for (const day of slots.slice(0, 5)) {
      slotsText += '📅 ' + day.label + ' (' + day.date + '):\n';
      slotsText += day.available.slice(0, 10).join(', ') + '\n\n';
    }
    slotsText += '[/HORARIOS_DISPONIBLES]';
  } else {
    slotsText = '[HORARIOS_DISPONIBLES]\nNo hay horarios disponibles esta semana. Pide disculpas y sugiere la próxima semana.\n[/HORARIOS_DISPONIBLES]';
  }
} catch(e) {
  slotsText = '[HORARIOS_DISPONIBLES]\nError al consultar agenda. Pide al lead que elija día y hora y confirma.\n[/HORARIOS_DISPONIBLES]';
}

return [{ json: { ...prev, available_slots: slotsText } }];

const fullResponse = $input.first().json.content[0].text;
const phone = $('Build Context').first().json.phone;
const sender_name = $('Build Context').first().json.sender_name;
const messages = $('Build Context').first().json.messages;

const metaIdx = fullResponse.indexOf('---FSC_META---');
let cleanResponse = fullResponse;
let meta = {};

if (metaIdx !== -1) {
  cleanResponse = fullResponse.substring(0, metaIdx).trim();
  const endIdx = fullResponse.indexOf('---END_FSC_META---');
  if (endIdx !== -1) {
    const metaStr = fullResponse.substring(metaIdx + 14, endIdx).trim();
    try { meta = JSON.parse(metaStr); } catch(e) { meta = {}; }
  }
}

// Add assistant response to history
messages.push({ role: 'assistant', content: cleanResponse });

return [{
  json: {
    phone,
    sender_name,
    response: cleanResponse,
    conversation_history: messages,
    lead_status: meta.status || 'en_calificacion',
    filtro_actual: meta.filtro_actual || 1,
    declara_impuestos: meta.declara_impuestos || null,
    regimen: meta.regimen || null,
    ingreso: meta.ingreso || null,
    situacion_laboral: meta.situacion_laboral || null,
    objetivo: meta.objetivo || null,
    prioridad: meta.prioridad || null,
    fecha_cita: meta.fecha_cita || null,
    hora_cita: meta.hora_cita || null
  }
}];
